#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long bags = (N + 9) / 10;
        printf("%lld\n", bags);
    }
    return 0;
}

